+func TestSystemTemplate_StructuralRegression(t *testing.T) {
+	resolver := &SectionResolver{
+		provider: "openai",
+		agent:    "coordinator",
+		agentFS:  embeddedAgents,
+		sources:  []SectionSource{embedSource{fs: embeddedPrompts, prefix: "prompts/sections/"}},
