+	}
+
+	// Profile tools
+	for _, td := range s.profile.ToolDefinitions() {
+		desc := strings.TrimSpace(td.Description)
+		if desc == "" {
+			desc = "(no description)"
+		}
+		data.ProfileTools = append(data.ProfileTools, ToolEntry{Name: td.Name, Description: desc})
+	}
+
+	// MCP tools
